import React from 'react';
import { motion } from 'framer-motion';
import { FadeTransition } from './PageTransition';
import './About.css';

const About = () => {
  const education = [
    {
      school: "University of Missouri, Columbia",
      degree: "Master of Science in Computer Science",
      period: "2023-2025",
      gpa: "GPA: 3.9"
    },
    {
      school: "Sreyas Institute of Engineering and Technology",
      degree: "Bachelor of Technology in Computer Science and Engineering",
      period: "2019-2023"
    }
  ];

  const experience = [
    {
      role: "Research Assistant",
      company: "University of Missouri, Columbia",
      period: "Jan 2024 – Present",
      points: [
        "Developing machine learning models, specifically residual CNNs, for power loss estimation in ferrite cores",
        "Implementing feature engineering techniques and physics-informed methods to enhance model accuracy",
        "Utilizing shoelace formula-based b-h curve estimation and residual corrections to refine predictions",
        "Conducting model training, evaluation, and optimization using PyTorch for efficient performance across materials",
        "Additionally, working on implementing FNN and LSTM for predicting core loss"
      ]
    },
    {
      role: "Teaching Assistant",
      company: "University of Missouri, Columbia",
      period: "Aug 2023 - Present",
      points: [
        "Assisted in the development and delivery of course materials for advanced cybersecurity topics",
        "Conducted lab sessions and provided one-on-one support to students",
        "Graded assignments and exams, ensuring timely feedback",
        "Collaborated with faculty to enhance the curriculum and improve student engagement"
      ]
    },
    {
      role: "Cyber Security Analyst Intern",
      company: "Supraja Technologies",
      period: "Jan 2022 – May 2022",
      points: [
        "Conducted comprehensive assessments of security breaches and attacks, identifying system vulnerabilities and providing recommendations for mitigation",
        "Developed and deployed custom scripts to address specific security threats, enhancing organizational cybersecurity posture",
        "Performed penetration testing to evaluate system defenses, documenting findings, and suggesting improvements",
        "Configured and utilized advanced security tools, generating detailed vulnerability reports for client remediation"
      ]
    },
    {
      role: "Ethical Hacker Intern",
      company: "Supraja Technologies",
      period: "Jun 2022 – Nov 2022",
      points: [
        "Identified and reported critical security vulnerabilities in web applications, contributing to improved security for various organizations",
        "Conducted Web Application Penetration Testing (WAPT) and bug hunting, enhancing security across multiple platforms",
        "Performed detailed security assessments, providing actionable insights to clients for vulnerability resolution"
      ]
    },
    {
      role: "Software Developer Intern",
      company: "Raise Digital | MERN STACK",
      period: "Nov 2022 – Mar 2023",
      points: [
        "Worked on full-stack web application development projects with an emphasis on both front-end and back-end technologies",
        "Contributed to backend services for an E-Commerce website using Express and MongoDB as Database",
        "Integrated deep learning features into the API, enhancing overall performance",
        "Utilized ReactJS and CSS for web design, ensuring a seamless user experience",
        "Developed an Online Job Searching Platform, applying skills in web architecture, real-time database integration, and user experience design",
        "Collaborated within an agile team environment, resolving real-time issues efficiently, and delivering high-quality code that met client standards"
      ]
    },
    {
      role: "Data Science Intern",
      company: "Personifwy",
      period: "Jun 2021 – Dec 2021",
      points: [
        "Conducted data analysis using Linear Discriminant Analysis and Hierarchical Clustering techniques, generating insights for business applications",
        "Developed an interactive chatbot leveraging NLP, NLTK, and BABI-META for training and testing, enhancing user engagement",
        "Created a hospital chatbot using Google Dialogflow, streamlining patient interactions and information retrieval"
      ]
    }
  ];

  const skills = {
    "Programming Languages": ["C", "C++", "Python", "MySQL", "PHP", "JavaScript", "SQL", "CSS", "R", "Java"],
    "Frameworks & Tools": ["Flask", "AWS", "ReactJS", "NodeJS", "Figma", "MySQL WorkBench", "Git", "Hadoop", "Django", "ExpressJS", "Angular", "MongoDB", "Docker", "Prometheus", "Grafana", "Jenkins", "Ansible", "GCP"],
    "Operating Systems": ["Windows", "Linux", "Ubuntu", "Kali Linux", "Mac"]
  };

  const publications = [
    {
      title: "Smart Attendance Using Facial Recognition",
      details: "International Peer-Journal (Volume 22, Issue 01) - 32 (YMER)"
    },
    {
      title: "Smart Home Appliances Operations Design by IoT devices",
      details: "International Peer-Journal (Volume 11, Issue VI) – (IJRASET)"
    }
  ];

  return (
    <FadeTransition>
      <section className="about">
        <div className="container">
          <motion.div 
            className="about-content"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <h2 className="section-title">About Me</h2>
            
            {/* Education Section */}
            <div className="education-section">
              <h3>Education</h3>
              <div className="timeline">
                {education.map((edu, index) => (
                  <motion.div 
                    className="timeline-item"
                    key={index}
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: index * 0.2 }}
                  >
                    <h4>{edu.school}</h4>
                    <p className="degree">{edu.degree}</p>
                    <p className="period">{edu.period}</p>
                    {edu.gpa && <p className="gpa">{edu.gpa}</p>}
                  </motion.div>
                ))}
              </div>
            </div>

            {/* Skills Section */}
            <div className="skills-section">
              <h3>Skills</h3>
              <div className="skills-grid">
                {Object.entries(skills).map(([category, skillList], index) => (
                  <motion.div 
                    className="skill-category"
                    key={index}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: index * 0.2 }}
                  >
                    <h4 className="skill-category-title">{category}</h4>
                    <ul className="skill-list">
                      {skillList.map((skill, skillIndex) => (
                        <li key={skillIndex} className="skill-item">{skill}</li>
                      ))}
                    </ul>
                  </motion.div>
                ))}
              </div>
            </div>

            {/* Experience Section */}
            <div className="experience-section">
              <h3>Experience</h3>
              <div className="experience-timeline">
                {experience.map((exp, index) => (
                  <motion.div 
                    className="experience-item"
                    key={index}
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: index * 0.2 }}
                  >
                    <h4>{exp.role}</h4>
                    <p className="company">{exp.company}</p>
                    <p className="period">{exp.period}</p>
                    <ul className="experience-points">
                      {exp.points.map((point, pointIndex) => (
                        <li key={pointIndex}>{point}</li>
                      ))}
                    </ul>
                  </motion.div>
                ))}
              </div>
            </div>

            {/* Publications Section */}
            <div className="publications-section">
              <h3>Publications</h3>
              <div className="publications-list">
                {publications.map((pub, index) => (
                  <motion.div 
                    className="publication-item"
                    key={index}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: index * 0.2 }}
                  >
                    <h4>{pub.title}</h4>
                    <p>{pub.details}</p>
                  </motion.div>
                ))}
              </div>
            </div>
          </motion.div>
        </div>
      </section>
    </FadeTransition>
  );
};

export default About;
